(function(){'use strict';function initScrollToTop(){const scrollToTopBtn=document.createElement('button');scrollToTopBtn.id='scroll-to-top';scrollToTopBtn.className='scroll-to-top';scrollToTopBtn.setAttribute('aria-label','Scroll to top of page');scrollToTopBtn.innerHTML='↑';document.body.appendChild(scrollToTopBtn);function toggleScrollButton(){if(window.pageYOffset>300){scrollToTopBtn.classList.add('visible');}else{scrollToTopBtn.classList.remove('visible');}}
function scrollToTop(){window.scrollTo({top:0,behavior:'smooth'});}
window.addEventListener('scroll',toggleScrollButton);scrollToTopBtn.addEventListener('click',scrollToTop);toggleScrollButton();}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initScrollToTop);}else{initScrollToTop();}})();